def build_index_from_json_documents(
    json_file_path: str,
    index_path: str,
    text_field: str = "text",
    metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    # Check if JSON file exists
    path = Path(json_file_path)
    if not path.exists():
        raise FileNotFoundError(f"JSON file not found at {json_file_path}")

    # Load JSON data
    try:
        with open(json_file_path, encoding='utf-8') as f:
            data = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON file")

    # Validate data structure
    if not isinstance(data, list):
        raise ValueError("JSON file must contain a list of documents")

    # Process documents
    documents = []
    for idx, doc in enumerate(data):
        # Check for required text field
        if text_field not in doc:
            raise ValueError(f"Document {idx} is missing required field '{text_field}'")

        # Create document structure for LeannBuilder
        new_doc = {
            'id': str(idx),
            'text': doc[text_field]
        }

        # Add metadata fields
        if metadata_fields is None:
            # Include all fields except text_field
            for key, value in doc.items():
                if key != text_field:
                    new_doc[key] = value
        else:
            # Include specified metadata fields
            for field in metadata_fields:
                if field in doc:
                    new_doc[field] = doc[field]

        documents.append(new_doc)

    # Build the index
    builder = LeannBuilder(backend_module_name=backend_name)
    builder.build(documents, index_path)

    return index_path

