def merge_search_results(
    results_by_index: Dict[str, List[SearchResult]],
    global_top_k: int = 10,
    deduplicate: bool = True
) -> List[SearchResult]:
    merged = []
    for index_res in results_by_index.values():
        merged.extend(index_res)
    merged.sort(key=lambda x: x.score, reverse=True)
    if deduplicate:
        seen_texts = set()
        unique = []
        for res in merged:
            text = res.text
            if text not in seen_texts:
                unique.append(res)
                seen_texts.add(text)
        merged = unique
    return merged[:global_top_k]

