def get_index_statistics(index_path: str) -> dict[str, Any]:
    try:
        pm = PassageManager(index_path)
        meta_list = pm.get_metadata()
        total = len(meta_list)
        fields = set()
        value_counts = defaultdict(Counter)
        for meta in meta_list:
            for k, v in meta.items():
                fields.add(k)
                value_counts[k][v] += 1
        return {
            "total_passages": total,
            "metadata_fields": sorted(fields),
            "field_value_counts": {k: dict(c) for k, c in value_counts.items()},
        }
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")
    except Exception as e:
