def analyze_index_coverage(index_path: str, required_fields: list[str]) -> dict[str, Any]:
    try:
        pm = PassageManager(index_path)
        meta_list = pm.get_metadata()
        total = len(meta_list)
        if total == 0:
            return {
                "coverage_percentage": 100.0 if not required_fields else 0.0,
                "field_coverage": {field: 100.0 for field in required_fields},
                "missing_fields": [],
            }
        all_covered = 0
        field_presence = defaultdict(int)
        required_set = set(required_fields)
        for meta in meta_list:
            if required_set.issubset(meta.keys()):
                all_covered += 1
            for field in required_fields:
                if field in meta:
                    field_presence[field] += 1
        coverage_pct = (all_covered / total) * 100
        field_coverages = {field: (field_presence[field] / total) * 100 for field in required_fields}
        missing = [field for field in required_fields if field_presence[field] == 0]
        return {
            "coverage_percentage": coverage_pct,
            "field_coverage": field_coverages,
            "missing_fields": missing,
        }
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")
    except Exception as e:
        raise RuntimeError(f"Failed to analyze index coverage: {e}")

