def export_index_metadata(index_path: str, output_file: str) -> dict[str, Any]:
    meta_path_str = f"{index_path}.meta.json"
    if not Path(meta_path_str).exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path_str}")

    with open(meta_path_str, encoding="utf-8") as f:
        meta = json.load(f)

    passages = []
    total_count = 0
    passage_sources = meta.get("passage_sources", [])
    for source in passage_sources:
        source_type = source.get("type")
        path = source.get("path")
        if not path:
            continue
        path_obj = Path(path)
        if path_obj.is_absolute():
            resolved_path = path
        else:
            meta_dir = Path(meta_path_str).parent
            resolved_path = str(meta_dir / path_obj)

        if source_type == "jsonl":
            try:
                with open(resolved_path, encoding="utf-8") as f:
                    for line_num, line in enumerate(f, 1):
                        if not line.strip():
                            continue
                        try:
                            data = json.loads(line.strip())
                            passages.append(
                                {
                                    "id": data.get("id"),
                                    "text": data.get("text"),
                                }
                            )
                        except json.JSONDecodeError:
                            print(
                                f"WARN: Skipping invalid JSON line {line_num} in {resolved_path}"
                            )
            except FileNotFoundError:
                print(f"WARN: Could not read passage source file {resolved_path}")
        elif source_type == "csv":
            try:
                import pandas as pd

                df = pd.read_csv(resolved_path)
                for _, row in df.iterrows():
                    passages.append(
                        {
                            "id": row["id"],
                            "text": row["text"],
                        }
                    )
            except ImportError:
                raise RuntimeError("pandas is required for CSV passage sources")
        # Add more source types as needed

    total_count = len(passages)
    export_data = {
        "version": meta.get("version", "1.0"),
        "backend_module": meta.get("backend_module"),
        "backend_kwargs": meta.get("backend_kwargs", {}),
        "passages": passages,
        "embedding_model": meta.get("embedding_model"),
        "embedding_mode": meta.get("embedding_mode"),
        "passage_sources": meta.get("passage_sources", []),  # Preserve source info
    }

    with open(output_file, "w", encoding="utf-8") as f:
        json.dump(export_data, f, indent=2)

    return {
        "exported_passages": total_count,
        "output_file": output_file,
        "status": "success",
    }

def import_index_from_metadata(
    export_file: str,
    index_path: str,
    backend_module_name: str = "leann.backends.hnsw",
    **kwargs,
) -> dict[str, Any]:
    if not Path(export_file).exists():
        raise FileNotFoundError(f"Export file not found: {export_file}")

    with open(export_file, encoding="utf-8") as f:
        data = json.load(f)

    required_keys = {"version", "passages", "backend_module", "backend_kwargs", "embedding_model"}
    if not required_keys.issubset(data.keys()):
        raise ValueError("Invalid export file format")

    passages = data["passages"]
    backend_module_str = data["backend_module"]
    backend_kwargs = data["backend_kwargs"]
    embedding_model = data.get("embedding_model")
    embedding_mode = data.get("embedding_mode")

    if not embedding_model:
        raise ValueError("No embedding model found in export data")

    # Create PassageManager and add passages
    passage_manager = PassageManager()
    for passage in passages:
        passage_manager.add_passage(passage["id"], passage["text"])

    # Generate embeddings
    print(
        f"Generating embeddings for {len(passages)} passages using {embedding_model} ({embedding_mode})"
    )
    if embedding_mode == "sentence-transformers":
        model = SentenceTransformer(embedding_model)
        texts = [p["text"] for p in passages]
        embeddings = model.encode(texts, show_progress_bar=True)
        model = None  # Free memory
    elif embedding_mode == "openai":
        # Handle OpenAI embedding
        try:
            import openai
        except ImportError:
            raise ImportError("openai package not installed")

        # Check API key
        api_key = os.getenv("OPENAI_API_KEY")
        if not api_key:
            raise RuntimeError("OPENAI_API_KEY environment variable not set")

        # Set up client
        client = openai.OpenAI(api_key=api_key)

        # Generate embeddings in batches
        embeddings = []
        texts = [p["text"] for p in passages]
        batch_size = 500  # Conservative batch size

        for i in range(0, len(texts), batch_size):
            batch_texts = texts[i : i + batch_size]
            response = client.embeddings.create(
                model=embedding_model,
                input=batch_texts,
            )
            batch_embeds = [embedding.embedding for embedding in response.data]
            embeddings.extend(batch_embeds)
    else:
        raise ValueError(f"Unsupported embedding mode: {embedding_mode}")

    # Build the index
    backend_module = importlib.import_module(backend_module_str)
    BuilderClass = getattr(backend_module, "Builder", None)
    if not BuilderClass:
        # Fallback to LeannBuilder if Builder not present
        BuilderClass = getattr(backend_module, "LeannBuilder", None)

    if not BuilderClass:
        raise ValueError(f"Backend module {backend_module_str} has no Builder class")

    # Merge any extra kwargs last
    build_kwargs = {**backend_kwargs, **kwargs}
    builder = BuilderClass(**build_kwargs)
    index = builder.build(embeddings, list(passage_manager.passages.keys()))

    # Save the index
    index.save(index_path)

    return {
        "index_path": index_path,
        "passages_imported": len(passages),
        "status": "success",
    }

