def search_with_result_expansion(
    index_path: str,
    query: str,
    expand_by_field: str,
    expansion_count: int = 1,
    top_k: int = 10
) -> List[SearchResult]:
    if expansion_count < 0:
        raise ValueError("expansion_count must be non-negative")

    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found at {index_path}")

    initial_results = searcher.search(
        query,
        top_k=top_k
    )

    field_values = []
    for result in initial_results:
        value = result.metadata.get(expand_by_field)
        if value is not None:
            field_values.append(value)
    unique_values = set(field_values)

    expanded = []
    for value in unique_values:
        meta_filter = {expand_by_field: value}
        try:
            exp_res = searcher.search(
                "",
                top_k=expansion_count,
                metadata_filters=meta_filter
            )
            expanded.extend(exp_res)
        except Exception as e:
            print(f"Warning: Could not expand by {meta_filter}: {e}")

    combined = initial_results + expanded
    return combined

