def search_with_result_merging(
    index_path: str,
    queries: List[str],
    top_k_per_query: int = 3,
    global_top_k: int = 10
) -> List[SearchResult]:
    if not os.path.exists(index_path):
        raise FileNotFoundError(f"Index file not found: {index_path}")
    if not queries:
        raise ValueError("queries list cannot be empty")

    searcher = LeannSearcher(index_path=index_path)

    all_results = []
    for query in queries:
        query_results = searcher.search(query, top_k=top_k_per_query)
        all_results.extend(query_results)

    deduped = {}
    for result in all_results:
        passage_id = result.metadata.get('id')
        if passage_id is None:
            continue
        current_score = result.score
        if passage_id not in deduped or current_score > deduped[passage_id].score:
            deduped[passage_id] = result

    sorted_results = sorted(deduped.values(), key=lambda x: x.score, reverse=True)
    return sorted_results[:global_top_k]

